  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `codigo_comprobante` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `cliente_id` bigint unsigned NOT NULL,
