  `monto` decimal(10,2) NOT NULL,
  `fecha_prestamo` date NOT NULL,
  `estado` enum('Activo','Pagado','Vencido') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Activo',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  `multa_por_retraso` decimal(10,2) DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `prestamos_codigo_unique` (`codigo`),
  UNIQUE KEY `codigo_comprobante` (`codigo_comprobante`),
  KEY `prestamos_cliente_id_foreign` (`cliente_id`),
  CONSTRAINT `prestamos_cliente_id_foreign` FOREIGN KEY (`cliente_id`) REFERENCES `clientes` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=452 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
